import {{ Injectable }} from '@nestjs/common';
import {{ SchedulerService }} from './models/scheduler.model';
import {{ SchedulerServiceRepository }} from './repositories/scheduler.repository';

@Injectable()
export class SchedulerServiceService {{
  constructor(
    private readonly repository: SchedulerServiceRepository,
  ) {{}}

  async findAll(): Promise<SchedulerService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<SchedulerService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<SchedulerService>): Promise<SchedulerService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<SchedulerService>): Promise<SchedulerService> {{
    return this.repository.update(id, data);
  }}
}}
